#include <stdio.h>
#include <string.h>
#define MOD 1000000007LL

long long modPow(long long base, long long exp) {
    long long res = 1;
    while (exp) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        long long cnt = 0;
        for (int i = 0; i < N; ++i) {
            char c = s[i];
            if (c=='c' || c=='g' || c=='l' || c=='r') cnt++;
        }
        printf("%lld\n", modPow(2, cnt));
    }
    return 0;
}

