const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
const amb = new Set(['c','g','l','r']);
function modPow(base, exp) {
  let b = BigInt(base);
  let e = BigInt(exp);
  let res = 1n;
  while (e > 0n) {
    if (e & 1n) res = (res * b) % MOD;
    b = (b * b) % MOD;
    e >>= 1n;
  }
  return res;
}
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const S = input[idx++];
  let cnt = 0;
  for (const ch of S) if (amb.has(ch)) ++cnt;
  results.push(modPow(2, cnt).toString());
}
console.log(results.join('\n'));

